// ── Helpers ───────────────────────────────────────────────────────────────────

export function getCategoryBySlug(slug: string): VocabCategory | undefined {
  return vocabCategories.find((c) => c.slug === slug);
}

export const totalWordCount = vocabCategories.reduce(
  (sum, cat) => sum + cat.words.length, 0
);
